import { redirect } from 'next/navigation';
import { getCurrentUser } from '@/lib/actions';
import { db } from '@/backend/lib/db';
import { DashboardClient } from '@/components/admin/dashboard-client';

export default async function DashboardPage() {
  const user = await getCurrentUser();
  if (!user) redirect('/');

  const isAdmin = await db.isAdmin(user.email);
  if (!isAdmin) redirect('/requests');

  const approvers = await db.getApprovers();

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold">Dashboard</h1>
        <p className="text-muted-foreground mt-1">
          Manage the approvers that users can assign to their requests.
        </p>
      </div>

      <DashboardClient initialApprovers={approvers} />
    </div>
  );
}

import { redirect } from 'next/navigation';
import { getCurrentUser } from '@/lib/actions';
import { db } from '@/backend/lib/db';
import { DashboardClient } from '@/components/admin/dashboard-client';

export default async function DashboardPage() {
  const user = await getCurrentUser();
  if (!user) redirect('/');

  const isAdmin = await db.isAdmin(user.email);
  if (!isAdmin) redirect('/requests');

  const approvers = await db.getApprovers();
  const autoApproveDays = await db.getSetting('auto_approve_days');

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold">Dashboard</h1>
        <p className="text-muted-foreground mt-1">
          Manage the approvers that users can assign to their requests and system settings.
        </p>
      </div>

      <DashboardClient initialApprovers={approvers} initialSettings={{ autoApproveDays }} />
    </div>
  );
}

import { NextResponse } from 'next/server';
import { db } from '@/backend/lib/db';
import { countWorkdays } from '@/lib/date-utils';
import { sendRequestResultNotification } from '@/backend/lib/mailer';

export const dynamic = 'force-dynamic';

export async function POST(req: Request) {
  const authHeader = req.headers.get('authorization');
  const cronSecret = process.env.CRON_SECRET;

  if (cronSecret && authHeader !== `Bearer ${cronSecret}`) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  try {
    const autoApproveDaysStr = await db.getSetting('auto_approve_days');
    if (!autoApproveDaysStr) {
      return NextResponse.json({ message: 'Auto-approve feature is disabled or not configured' }, { status: 200 });
    }

    const autoApproveDaysLimit = parseInt(autoApproveDaysStr, 10);
    if (isNaN(autoApproveDaysLimit) || autoApproveDaysLimit <= 0) {
      return NextResponse.json({ message: 'Auto-approve days is set to an invalid value' }, { status: 200 });
    }

    const pendingRequests = await db.getAllRequests({ status: 'pending' });

    let approvedCount = 0;
    const now = new Date();

    for (const request of pendingRequests) {
      const workdaysElapsed = countWorkdays(request.created_at, now) - 1; // subtract 1 so day of creation isn't counted as an elapsed day, depending on desired logic

      if (workdaysElapsed >= autoApproveDaysLimit) {
        // Update request to approved
        await db.updateRequest(request.id, {
          status: 'approved',
          admin_notes: `Automatically approved after ${autoApproveDaysLimit} working days.`
        });

        // Mark all linked pending approvals as approved
        const approvals = await db.getApprovalsByRequest(request.id);
        for (const approval of approvals) {
          if (approval.status === 'pending') {
            await db.updateApproval(approval.id, {
              status: 'approved',
              decision_notes: 'System Auto-Approve',
              responded_at: new Date()
            });
          }
        }

        const updatedRequest = await db.getRequestById(request.id);
        if (updatedRequest) {
          await sendRequestResultNotification(updatedRequest);
        }

        approvedCount++;
      }
    }

    return NextResponse.json({
      success: true,
      evaluated: pendingRequests.length,
      approved: approvedCount
    }, { status: 200 });
  } catch (error) {
    console.error('Failed to run auto-approve cron:', error);
    return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { db } from '@/backend/lib/db';
import { countWorkdays } from '@/lib/date-utils';
import { sendRequestResultNotification } from '@/backend/lib/mailer';

export const dynamic = 'force-dynamic';

export async function POST(req: Request) {
  const authHeader = req.headers.get('authorization');
  const cronSecret = process.env.CRON_SECRET;

  if (cronSecret && authHeader !== `Bearer ${cronSecret}`) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  try {
    const autoApproveDaysStr = await db.getSetting('auto_approve_days');
    if (!autoApproveDaysStr) {
      return NextResponse.json({ message: 'Auto-approve feature is disabled or not configured' }, { status: 200 });
    }

    const autoApproveDaysLimit = parseInt(autoApproveDaysStr, 10);
    if (isNaN(autoApproveDaysLimit) || autoApproveDaysLimit <= 0) {
      return NextResponse.json({ message: 'Auto-approve days is set to an invalid value' }, { status: 200 });
    }

    const pendingRequests = await db.getAllRequests({ status: 'pending' });

    let approvedCount = 0;
    const now = new Date();

    for (const request of pendingRequests) {
      // countWorkdays includes both start and end, so e.g. Monday to Tuesday is 2 days. 
      // If we want "approved after X full working days", we subtract 1.
      const workdaysElapsed = countWorkdays(request.created_at, now) - 1; 

      if (workdaysElapsed >= autoApproveDaysLimit) {
        // Update request to approved
        await db.updateRequest(request.id, {
          status: 'approved',
          admin_notes: `Automatically approved after ${autoApproveDaysLimit} working days.`
        });

        // Mark all linked pending approvals as approved
        const approvals = await db.getApprovalsByRequest(request.id);
        for (const approval of approvals) {
          if (approval.status === 'pending') {
            await db.updateApproval(approval.id, {
              status: 'approved',
              decision_notes: 'System Auto-Approve',
              responded_at: new Date()
            });
          }
        }

        const updatedRequest = await db.getRequestById(request.id);
        if (updatedRequest) {
          await sendRequestResultNotification(updatedRequest);
        }

        approvedCount++;
      }
    }

    return NextResponse.json({ 
      success: true,
      evaluated: pendingRequests.length,
      approved: approvedCount
    }, { status: 200 });
  } catch (error) {
    console.error('Failed to run auto-approve cron:', error);
    return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
  }
}

-- Holiday Request Management System Schema
CREATE TABLE IF NOT EXISTS requests ( id INTEGER PRIMARY KEY AUTOINCREMENT, user_email TEXT NOT NULL, user_name TEXT, user_picture TEXT, request_time DATETIME DEFAULT CURRENT_TIMESTAMP, start_date DATE NOT NULL, end_date DATE NOT NULL, request_type TEXT DEFAULT 'vacation', status TEXT DEFAULT 'pending', notes TEXT, admin_notes TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE IF NOT EXISTS approvals ( id INTEGER PRIMARY KEY AUTOINCREMENT, request_id INTEGER NOT NULL, approver_email TEXT NOT NULL, approver_name TEXT, approver_role TEXT, status TEXT DEFAULT 'pending', decision_notes TEXT, responded_at DATETIME, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (request_id) REFERENCES requests(id) ON DELETE CASCADE );
-- Admins: users who can access the dashboard and manage approvers CREATE TABLE IF NOT EXISTS admins ( id INTEGER PRIMARY KEY AUTOINCREMENT, email TEXT NOT NULL UNIQUE, added_at DATETIME DEFAULT CURRENT_TIMESTAMP );
-- Approvers: configurable pool of individuals or groups that users pick from when creating requests. -- For groups, group_emails stores a JSON array of member emails; any one member can approve. CREATE TABLE IF NOT EXISTS approvers ( id INTEGER PRIMARY KEY AUTOINCREMENT, type TEXT NOT NULL CHECK(type IN ('individual', 'group')), name TEXT NOT NULL, email TEXT NOT NULL, role TEXT, group_emails TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP );
CREATE INDEX IF NOT EXISTS idx_requests_user_email_status ON requests(user_email, status); CREATE INDEX IF NOT EXISTS idx_requests_status_created_at ON requests(status, created_at); CREATE INDEX IF NOT EXISTS idx_approvals_request_id ON approvals(request_id); CREATE INDEX IF NOT EXISTS idx_approvals_approver_email_status ON approvals(approver_email, status); CREATE INDEX IF NOT EXISTS idx_approvers_type ON approvers(type);

-- Holiday Request Management System Schema
CREATE TABLE IF NOT EXISTS requests ( id INTEGER PRIMARY KEY AUTOINCREMENT, user_email TEXT NOT NULL, user_name TEXT, user_picture TEXT, request_time DATETIME DEFAULT CURRENT_TIMESTAMP, start_date DATE NOT NULL, end_date DATE NOT NULL, request_type TEXT DEFAULT 'vacation', status TEXT DEFAULT 'pending', notes TEXT, admin_notes TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE IF NOT EXISTS approvals ( id INTEGER PRIMARY KEY AUTOINCREMENT, request_id INTEGER NOT NULL, approver_email TEXT NOT NULL, approver_name TEXT, approver_role TEXT, status TEXT DEFAULT 'pending', decision_notes TEXT, responded_at DATETIME, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (request_id) REFERENCES requests(id) ON DELETE CASCADE );
-- Admins: users who can access the dashboard and manage approvers CREATE TABLE IF NOT EXISTS admins ( id INTEGER PRIMARY KEY AUTOINCREMENT, email TEXT NOT NULL UNIQUE, added_at DATETIME DEFAULT CURRENT_TIMESTAMP );
-- Approvers: configurable pool of individuals or groups that users pick from when creating requests. -- For groups, group_emails stores a JSON array of member emails; any one member can approve. CREATE TABLE IF NOT EXISTS approvers ( id INTEGER PRIMARY KEY AUTOINCREMENT, type TEXT NOT NULL CHECK(type IN ('individual', 'group')), name TEXT NOT NULL, email TEXT NOT NULL, role TEXT, group_emails TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE IF NOT EXISTS settings ( key TEXT PRIMARY KEY, value TEXT NOT NULL, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP );
CREATE INDEX IF NOT EXISTS idx_requests_user_email_status ON requests(user_email, status); CREATE INDEX IF NOT EXISTS idx_requests_status_created_at ON requests(status, created_at); CREATE INDEX IF NOT EXISTS idx_approvals_request_id ON approvals(request_id); CREATE INDEX IF NOT EXISTS idx_approvals_approver_email_status ON approvals(approver_email, status); CREATE INDEX IF NOT EXISTS idx_approvers_type ON approvers(type);

import Database from 'better-sqlite3';
import { readFileSync } from 'fs';
import { join } from 'path';
import type { DatabaseAdapter, Request, Approval, RequestFilters, Admin, Approver } from './database';

function toDate(value: string | null | undefined): Date {
  if (!value) return new Date();
  return new Date(value);
}

function toDateOrUndefined(value: string | null | undefined): Date | undefined {
  if (!value) return undefined;
  return new Date(value);
}

function toISOString(date: Date | string | undefined | null): string | null {
  if (!date) return null;
  if (typeof date === 'string') return date;
  return date.toISOString();
}

interface RequestRow {
  id: number;
  user_email: string;
  user_name: string | null;
  user_picture: string | null;
  request_time: string;
  start_date: string;
  end_date: string;
  request_type: string;
  status: string;
  notes: string | null;
  admin_notes: string | null;
  created_at: string;
  updated_at: string;
}

interface ApprovalRow {
  id: number;
  request_id: number;
  approver_email: string;
  approver_name: string | null;
  approver_role: string | null;
  status: string;
  decision_notes: string | null;
  responded_at: string | null;
  created_at: string;
}

interface AdminRow {
  id: number;
  email: string;
  added_at: string;
}

interface ApproverRow {
  id: number;
  type: string;
  name: string;
  email: string;
  role: string | null;
  group_emails: string | null;
  created_at: string;
}

function rowToRequest(row: RequestRow): Request {
  return {
    id: row.id,
    user_email: row.user_email,
    user_name: row.user_name ?? undefined,
    user_picture: row.user_picture ?? undefined,
    request_time: toDate(row.request_time),
    start_date: toDate(row.start_date),
    end_date: toDate(row.end_date),
    request_type: row.request_type,
    status: row.status as Request['status'],
    notes: row.notes ?? undefined,
    admin_notes: row.admin_notes ?? undefined,
    created_at: toDate(row.created_at),
    updated_at: toDate(row.updated_at),
  };
}

function rowToApproval(row: ApprovalRow): Approval {
  return {
    id: row.id,
    request_id: row.request_id,
    approver_email: row.approver_email,
    approver_name: row.approver_name ?? undefined,
    approver_role: row.approver_role ?? undefined,
    status: row.status as Approval['status'],
    decision_notes: row.decision_notes ?? undefined,
    responded_at: toDateOrUndefined(row.responded_at),
    created_at: toDate(row.created_at),
  };
}

function rowToAdmin(row: AdminRow): Admin {
  return {
    id: row.id,
    email: row.email,
    added_at: toDate(row.added_at),
  };
}

function rowToApprover(row: ApproverRow): Approver {
  return {
    id: row.id,
    type: row.type as Approver['type'],
    name: row.name,
    email: row.email,
    role: row.role ?? undefined,
    group_emails: row.group_emails ? (JSON.parse(row.group_emails) as string[]) : undefined,
    created_at: toDate(row.created_at),
  };
}

export class SQLiteAdapter implements DatabaseAdapter {
  private db: Database.Database;
  private stmtGetRequestById: Database.Statement;
  private stmtGetRequestByUser: Database.Statement;
  private stmtDeleteRequest: Database.Statement;
  private stmtGetApprovalsByRequest: Database.Statement;
  private stmtGetApprovalsByApprover: Database.Statement;
  private stmtGetAdmins: Database.Statement;
  private stmtIsAdmin: Database.Statement;
  private stmtGetApprovers: Database.Statement;

  constructor(dbPath: string) {
    this.db = new Database(dbPath);
    this.db.pragma('journal_mode = WAL');
    this.db.pragma('foreign_keys = ON');

    this.stmtGetRequestById = this.db.prepare('SELECT * FROM requests WHERE id = ?');
    this.stmtGetRequestByUser = this.db.prepare('SELECT * FROM requests WHERE user_email = ? ORDER BY created_at DESC');
    this.stmtDeleteRequest = this.db.prepare('DELETE FROM requests WHERE id = ?');
    this.stmtGetApprovalsByRequest = this.db.prepare('SELECT * FROM approvals WHERE request_id = ? ORDER BY created_at ASC');
    this.stmtGetApprovalsByApprover = this.db.prepare('SELECT * FROM approvals WHERE approver_email = ? ORDER BY created_at DESC');
    this.stmtGetAdmins = this.db.prepare('SELECT * FROM admins ORDER BY added_at ASC');
    this.stmtIsAdmin = this.db.prepare('SELECT id FROM admins WHERE email = ?');
    this.stmtGetApprovers = this.db.prepare('SELECT * FROM approvers ORDER BY created_at ASC');
  }

  async initialize(): Promise<void> {
    const schemaPath = join(process.cwd(), 'backend', 'db', 'schema.sql');
    try {
      const schema = readFileSync(schemaPath, 'utf-8');
      this.db.exec(schema);
    } catch (error) {
      console.error('Failed to read schema file:', error);
      throw error;
    }
  }

  async close(): Promise<void> {
    this.db.close();
  }

  async createRequest(data: Omit<Request, 'id' | 'created_at' | 'updated_at'>): Promise<Request> {
    const stmt = this.db.prepare(`
      INSERT INTO requests (user_email, user_name, user_picture, request_time, start_date, end_date, request_type, status, notes, admin_notes)
      VALUES (@user_email, @user_name, @user_picture, @request_time, @start_date, @end_date, @request_type, @status, @notes, @admin_notes)
    `);
    const result = stmt.run({
      user_email: data.user_email,
      user_name: data.user_name ?? null,
      user_picture: data.user_picture ?? null,
      request_time: toISOString(data.request_time),
      start_date: toISOString(data.start_date),
      end_date: toISOString(data.end_date),
      request_type: data.request_type,
      status: data.status,
      notes: data.notes ?? null,
      admin_notes: data.admin_notes ?? null,
    });
    const row = this.stmtGetRequestById.get(result.lastInsertRowid) as RequestRow;
    return rowToRequest(row);
  }

  async getRequestById(id: number): Promise<Request | null> {
    const row = this.stmtGetRequestById.get(id) as RequestRow | undefined;
    return row ? rowToRequest(row) : null;
  }

  async getRequestsByUser(userEmail: string): Promise<Request[]> {
    const rows = this.stmtGetRequestByUser.all(userEmail) as RequestRow[];
    return rows.map(rowToRequest);
  }

  async getAllRequests(filters?: RequestFilters): Promise<Request[]> {
    let query = 'SELECT * FROM requests WHERE 1=1';
    const params: (string | number | null)[] = [];

    if (filters?.status) {
      query += ' AND status = ?';
      params.push(filters.status);
    }
    if (filters?.user_email) {
      query += ' AND user_email = ?';
      params.push(filters.user_email);
    }
    if (filters?.request_type) {
      query += ' AND request_type = ?';
      params.push(filters.request_type);
    }
    if (filters?.start_date_from) {
      query += ' AND start_date >= ?';
      params.push(toISOString(filters.start_date_from));
    }
    if (filters?.start_date_to) {
      query += ' AND start_date <= ?';
      params.push(toISOString(filters.start_date_to));
    }

    query += ' ORDER BY created_at DESC';

    if (filters?.limit !== undefined) {
      query += ' LIMIT ?';
      params.push(filters.limit);
      if (filters?.offset !== undefined) {
        query += ' OFFSET ?';
        params.push(filters.offset);
      }
    }

    const rows = this.db.prepare(query).all(...params) as RequestRow[];
    return rows.map(rowToRequest);
  }

  async updateRequest(id: number, data: Partial<Request>): Promise<Request> {
    const fields: string[] = [];
    const params: (string | number | null)[] = [];

    if (data.user_email !== undefined) { fields.push('user_email = ?'); params.push(data.user_email); }
    if (data.user_name !== undefined) { fields.push('user_name = ?'); params.push(data.user_name ?? null); }
    if (data.user_picture !== undefined) { fields.push('user_picture = ?'); params.push(data.user_picture ?? null); }
    if (data.start_date !== undefined) { fields.push('start_date = ?'); params.push(toISOString(data.start_date)); }
    if (data.end_date !== undefined) { fields.push('end_date = ?'); params.push(toISOString(data.end_date)); }
    if (data.request_type !== undefined) { fields.push('request_type = ?'); params.push(data.request_type); }
    if (data.status !== undefined) { fields.push('status = ?'); params.push(data.status); }
    if (data.notes !== undefined) { fields.push('notes = ?'); params.push(data.notes ?? null); }
    if (data.admin_notes !== undefined) { fields.push('admin_notes = ?'); params.push(data.admin_notes ?? null); }

    if (fields.length === 0) {
      const existing = await this.getRequestById(id);
      if (!existing) throw new Error(`Request with id ${id} not found`);
      return existing;
    }

    fields.push('updated_at = ?');
    params.push(new Date().toISOString());
    params.push(id);

    this.db.prepare(`UPDATE requests SET ${fields.join(', ')} WHERE id = ?`).run(...params);
    const updated = await this.getRequestById(id);
    if (!updated) throw new Error(`Request with id ${id} not found`);
    return updated;
  }

  async deleteRequest(id: number): Promise<void> {
    this.stmtDeleteRequest.run(id);
  }

  async createApproval(data: Omit<Approval, 'id' | 'created_at'>): Promise<Approval> {
    const stmt = this.db.prepare(`
      INSERT INTO approvals (request_id, approver_email, approver_name, approver_role, status, decision_notes, responded_at)
      VALUES (@request_id, @approver_email, @approver_name, @approver_role, @status, @decision_notes, @responded_at)
    `);
    const result = stmt.run({
      request_id: data.request_id,
      approver_email: data.approver_email,
      approver_name: data.approver_name ?? null,
      approver_role: data.approver_role ?? null,
      status: data.status,
      decision_notes: data.decision_notes ?? null,
      responded_at: toISOString(data.responded_at),
    });
    const row = this.db.prepare('SELECT * FROM approvals WHERE id = ?').get(result.lastInsertRowid) as ApprovalRow;
    return rowToApproval(row);
  }

  async getApprovalsByRequest(requestId: number): Promise<Approval[]> {
    const rows = this.stmtGetApprovalsByRequest.all(requestId) as ApprovalRow[];
    return rows.map(rowToApproval);
  }

  async getApprovalsByRequests(requestIds: number[]): Promise<Approval[]> {
    if (requestIds.length === 0) return [];
    const placeholders = requestIds.map(() => '?').join(',');
    const query = `SELECT * FROM approvals WHERE request_id IN (${placeholders}) ORDER BY created_at ASC`;
    const rows = this.db.prepare(query).all(...requestIds) as ApprovalRow[];
    return rows.map(rowToApproval);
  }

  async getApprovalsByApprover(approverEmail: string): Promise<Approval[]> {
    const rows = this.stmtGetApprovalsByApprover.all(approverEmail) as ApprovalRow[];
    return rows.map(rowToApproval);
  }

  async updateApproval(id: number, data: Partial<Approval>): Promise<Approval> {
    const fields: string[] = [];
    const params: (string | number | null)[] = [];

    if (data.approver_email !== undefined) { fields.push('approver_email = ?'); params.push(data.approver_email); }
    if (data.approver_name !== undefined) { fields.push('approver_name = ?'); params.push(data.approver_name ?? null); }
    if (data.approver_role !== undefined) { fields.push('approver_role = ?'); params.push(data.approver_role ?? null); }
    if (data.status !== undefined) { fields.push('status = ?'); params.push(data.status); }
    if (data.decision_notes !== undefined) { fields.push('decision_notes = ?'); params.push(data.decision_notes ?? null); }
    if (data.responded_at !== undefined) { fields.push('responded_at = ?'); params.push(toISOString(data.responded_at)); }

    params.push(id);

    if (fields.length === 0) {
      const row = this.db.prepare('SELECT * FROM approvals WHERE id = ?').get(id) as ApprovalRow | undefined;
      if (!row) throw new Error(`Approval with id ${id} not found`);
      return rowToApproval(row);
    }

    this.db.prepare(`UPDATE approvals SET ${fields.join(', ')} WHERE id = ?`).run(...params);
    const row = this.db.prepare('SELECT * FROM approvals WHERE id = ?').get(id) as ApprovalRow | undefined;
    if (!row) throw new Error(`Approval with id ${id} not found`);
    return rowToApproval(row);
  }

  async getAdmins(): Promise<Admin[]> {
    const rows = this.stmtGetAdmins.all() as AdminRow[];
    return rows.map(rowToAdmin);
  }

  async addAdmin(email: string): Promise<Admin> {
    this.db.prepare('INSERT OR IGNORE INTO admins (email) VALUES (?)').run(email);
    const row = this.db.prepare('SELECT * FROM admins WHERE email = ?').get(email) as AdminRow;
    return rowToAdmin(row);
  }

  async removeAdmin(email: string): Promise<void> {
    this.db.prepare('DELETE FROM admins WHERE email = ?').run(email);
  }

  async isAdmin(email: string): Promise<boolean> {
    const row = this.stmtIsAdmin.get(email);
    return row !== undefined;
  }

  async getApprovers(): Promise<Approver[]> {
    const rows = this.stmtGetApprovers.all() as ApproverRow[];
    return rows.map(rowToApprover);
  }

  async addApprover(data: Omit<Approver, 'id' | 'created_at'>): Promise<Approver> {
    const stmt = this.db.prepare(`
      INSERT INTO approvers (type, name, email, role, group_emails)
      VALUES (@type, @name, @email, @role, @group_emails)
    `);
    const result = stmt.run({
      type: data.type,
      name: data.name,
      email: data.email,
      role: data.role ?? null,
      group_emails: data.group_emails ? JSON.stringify(data.group_emails) : null,
    });
    const row = this.db.prepare('SELECT * FROM approvers WHERE id = ?').get(result.lastInsertRowid) as ApproverRow;
    return rowToApprover(row);
  }

  async removeApprover(id: number): Promise<void> {
    this.db.prepare('DELETE FROM approvers WHERE id = ?').run(id);
  }
}

